import{_ as r,M as n,p as o,q as s,R as t,t as e,N as i,a1 as d}from"./framework-5866ffd3.js";const h={},c=t("h1",{id:"transformer",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#transformer","aria-hidden":"true"},"#"),e(" Transformer")],-1),u={href:"https://arxiv.org/abs/1706.03762",target:"_blank",rel:"noopener noreferrer"},l=d('<p>Transformer 是一种基于**自注意力（Self-Attention）**的序列建模架构，不依赖循环或卷积即可对序列进行编码，成为 BERT、GPT 等大模型的基础。</p><hr><h2 id="自注意力-self-attention" tabindex="-1"><a class="header-anchor" href="#自注意力-self-attention" aria-hidden="true">#</a> 自注意力（Self-Attention）</h2><p>区别于传统 RNN 需要按位置逐个传递、串行计算，自注意力允许<strong>所有位置同时并行计算</strong>，并通过注意力权重直接建模任意位置之间的依赖关系，因此更易捕捉长程依赖，也便于并行加速。</p><h3 id="多头注意力-multi-head-attention" tabindex="-1"><a class="header-anchor" href="#多头注意力-multi-head-attention" aria-hidden="true">#</a> 多头注意力（Multi-Head Attention）</h3><p>将 Q、K、V 在特征维度上拆成多组，每组独立做一次自注意力，最后把多组输出拼接再线性变换。这样模型可以在不同子空间里学习不同类型的依赖关系（如局部语法、长程指代等）。</p><h2 id="q、k、v" tabindex="-1"><a class="header-anchor" href="#q、k、v" aria-hidden="true">#</a> Q、K、V</h2><p>自注意力通过三组向量表示每个位置的角色：</p><ul><li><strong>Q（Query）</strong>：当前位置「想找什么」—— 用于与其它位置的 Key 做匹配。</li><li><strong>K（Key）</strong>：当前位置「能提供什么」—— 供其它位置的 Query 来检索。</li><li><strong>V（Value）</strong>：当前位置的「实际内容」—— 匹配后用于加权聚合的信息。</li></ul><p>模型通过训练学习 W<sup>Q</sup>、W<sup>K</sup>、W<sup>V</sup> 等投影矩阵，将输入映射为 Q、K、V；运行时可理解为用这些矩阵表达模型学到的「如何查询、如何提供、如何聚合」的知识。</p><h3 id="kv-cache" tabindex="-1"><a class="header-anchor" href="#kv-cache" aria-hidden="true">#</a> KV Cache</h3><p>推理阶段是自回归的（逐个生成新 token），例如 &quot;A&quot; → &quot;AB&quot; → &quot;ABC&quot; → &quot;ABCD&quot;。若生成 D 时仍对整段序列重新算一遍注意力，会产生大量冗余计算。</p><p>QKV 结构适合做 <strong>KV Cache</strong>：生成 D 时只需新算 (Q_D)、(K_D)、(V_D)，而注意力计算所依赖的 (K_A)、(V_A)、(K_B)、(V_B) 等可直接复用上一轮已算好的结果；当前步只关心「用 D 的 Query 去查前面所有 Key/Value」，因此不需要保留或复用之前的 (Q_A)、(Q_B) 等。</p><h3 id="缩放点积注意力-scaled-dot-product-attention" tabindex="-1"><a class="header-anchor" href="#缩放点积注意力-scaled-dot-product-attention" aria-hidden="true">#</a> 缩放点积注意力（Scaled Dot-Product Attention）</h3><p>核心计算为：用 Query 与所有 Key 做点积得到相似度，经 <strong>softmax</strong> 得到注意力权重，再对 Value 加权求和。公式中会对点积结果除以 <strong>√(d<sub>k</sub>)</strong>（d<sub>k</sub> 为 Key 维度），以缓解维度较大时点积数值过大导致 softmax 梯度变小的问题。</p>',15);function p(_,f){const a=n("ExternalLinkIcon");return o(),s("div",null,[c,t("p",null,[e("论文："),t("a",u,[e("Attention Is All You Need"),i(a)]),e("（2017）")]),l])}const V=r(h,[["render",p],["__file","transfomer.html.vue"]]);export{V as default};
